use std::collections::BinaryHeap;
use std::cmp::Reverse;

// Helper function for Dijkstra's algorithm
// Finds shortest path distances from a source node 'start' using the provided adjacency list.
// Weights must be non-negative.
fn dijkstra(n: usize, adj: &Vec<Vec<(usize, i64)>>, start: usize) -> Vec<i64> {
    const INF: i64 = std::i64::MAX / 2; // Use a large number safely less than MAX to prevent overflow during additions
    let mut dist: Vec<i64> = vec![INF; n];
    let mut pq = BinaryHeap::new();

    dist[start] = 0;
    // Store (Reverse(distance), node) for min-heap behavior
    pq.push(Reverse((0i64, start)));

    while let Some(Reverse((d, u))) = pq.pop() {
        if d > dist[u] {
            continue;
        }

        for &(v, weight) in adj[u].iter() {
            let new_dist = d + weight;
            if new_dist < dist[v] {
                dist[v] = new_dist;
                pq.push(Reverse((new_dist, v)));
            }
        }
    }
    dist
}

fn solve(n_i64: i64, prices: Vec<i64>, roads: Vec<Vec<i64>>) -> Vec<i64> {
    let n = n_i64 as usize;

    // 1. Build Graphs
    // Adj_E: Graph for Empty Travel (weight = cost)
    // Adj_F: Graph for Filled Travel (weight = cost * tax)
    let mut adj_e: Vec<Vec<(usize, i64)>> = vec![vec![]; n];
    let mut adj_f: Vec<Vec<(usize, i64)>> = vec![vec![]; n];

    for &road in roads.iter() {
        let u = road[0] as usize;
        let v = road[1] as usize;
        let cost = road[2];
        let tax = road[3];

        // Empty travel: weight = cost
        adj_e[u].push((v, cost));
        adj_e[v].push((u, cost));

        // Filled travel: weight = cost * tax
        let filled_cost = cost * tax;
        adj_f[u].push((v, filled_cost));
        adj_f[v].push((u, filled_cost));
    }

    // 2. Run APSP using Dijkstra N times

    // D_E[i][j] = Shortest path distance i -> j (Empty)
    let mut d_e_all: Vec<Vec<i64>> = Vec::with_capacity(n);
    for i in 0..n {
        d_e_all.push(dijkstra(n, &adj_e, i));
    }

    // D_F[i][j] = Shortest path distance i -> j (Filled)
    let mut d_f_all: Vec<Vec<i64>> = Vec::with_capacity(n);
    for i in 0..n {
        d_f_all.push(dijkstra(n, &adj_f, i));
    }

    // 3. Calculate Final Answer
    let mut ans: Vec<i64> = vec![0; n];

    for i in 0..n {
        let p_i = prices[i];
        let mut min_cost = p_i;

        // Check alternative routes through store j
        for j in 0..n {
            if i == j {
                // If j=i, the travel costs are 0, total cost is P_i (already covered)
                continue;
            }

            let d_e_ij = d_e_all[i][j];
            let d_f_ji = d_f_all[j][i]; 
            // Since graphs are symmetric, D_F[j][i] == D_F[i][j]

            // Check if paths exist (i.e., distance is not INF)
            if d_e_ij != std::i64::MAX / 2 && d_f_ji != std::i64::MAX / 2 {
                // Total cost = Empty Path (i->j) + Price at j + Filled Path (j->i)
                // Note: d_e_ij + d_f_ji + p_j can potentially overflow if INF was used carelessly, 
                // but since we checked for INF and INF is safely chosen, standard addition is fine.
                let total_cost = d_e_ij + prices[j] + d_f_ji;

                if total_cost < min_cost {
                    min_cost = total_cost;
                }
            }
        }
        ans[i] = min_cost;
    }

    ans
