use std::collections::BinaryHeap;
use std::cmp::Ordering;

// Helper struct for Dijkstra's priority queue
#[derive(Copy, Clone, Eq, PartialEq)]
struct State {
    cost: i64,
    position: usize,
}

// Implement comparison traits for BinaryHeap (Min-Heap simulation using reverse ordering)
impl Ord for State {
    fn cmp(&self, other: &Self) -> Ordering {
        // We want a min-heap, so we reverse the comparison on cost
        other.cost.cmp(&self.cost)
    }
}

impl PartialOrd for State {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}


fn dijkstra(n: usize, adj: &Vec<Vec<(usize, i64)>>, start_node: usize) -> Vec<i64> {
    const INF: i64 = 1_000_000_000_000_000_000; // Large enough infinity

    let mut dist: Vec<i64> = vec![INF; n];
    let mut heap = BinaryHeap::new();

    dist[start_node] = 0;
    heap.push(State { cost: 0, position: start_node });

    while let Some(State { cost, position }) = heap.pop() {
        if cost > dist[position] {
            continue;
        }

        for &(neighbor, weight) in &adj[position] {
            let new_cost = cost + weight;
            if new_cost < dist[neighbor] {
                dist[neighbor] = new_cost;
                heap.push(State { cost: new_cost, position: neighbor });
            }
        }
    }
    dist
}

fn solve(n_i64: i64, prices: Vec<i64>, roads: Vec<Vec<i64>>) -> Vec<i64> {
    let n = n_i64 as usize;

    // --- 1. Build Graphs for Empty and Full travel ---

    // adj_empty[u] = list of (v, cost_empty)
    let mut adj_empty: Vec<Vec<(usize, i64)>> = vec![Vec::new(); n];
    // adj_full[u] = list of (v, cost_full)
    let mut adj_full: Vec<Vec<(usize, i64)>> = vec![Vec::new(); n];

    for road in roads {
        let u = road[0] as usize;
        let v = road[1] as usize;
        let cost = road[2];
        let tax = road[3];

        // Empty state
        adj_empty[u].push((v, cost));
        adj_empty[v].push((u, cost));

        // Full state
        // Calculate cost * tax. Since cost and tax are i64, we must ensure the product doesn't overflow i64 if possible, 
        // though given constraints (10^9 * 100 = 10^11), i64 is safe.
        let cost_full = cost * tax;
        adj_full[u].push((v, cost_full));
        adj_full[v].push((u, cost_full));
    }

    // --- 2. Calculate All-Pairs Shortest Paths ---

    // DE[i][j]: Shortest path cost i -> j when empty
    let mut DE: Vec<Vec<i64>> = vec![vec![0; n]; n];
    // DF[j][i]: Shortest path cost j -> i when full
    let mut DF: Vec<Vec<i64>> = vec![vec![0; n]; n];

    for i in 0..n {
        // Calculate DE[i][*]
        let dist_empty = dijkstra(n, &adj_empty, i);
        for j in 0..n {
            DE[i][j] = dist_empty[j];
        }

