        for j in 0..n {
            DF[j][i] = dist_full[j];
        }
    }


    // --- 3. Calculate Minimum Cost for each store i ---

    let mut ans = vec![0; n];
    const INF: i64 = 1_000_000_000_000_000_000;

    for i in 0..n {
        // Option 1: Buy locally
        let mut min_cost = prices[i];

        // Option 2: Travel i -> j -> i, buy at j
        for j in 0..n {
            // Path: i --(Empty)--> j --(Buy)--> i

            // Check if paths exist (costs are not INF)
            if DE[i][j] != INF && DF[j][i] != INF {
                // Total cost = Travel Empty (i->j) + Buy Price (j) + Travel Full (j->i)
                let current_total_cost = DE[i][j] + prices[j] + DF[j][i];

                if current_total_cost < min_cost {
                    min_cost = current_total_cost;
                }
            }
        }
        ans[i] = min_cost;
    }

    ans
