// Define a type alias for clarity: (cost, node_index)
type State = (i64, usize);

/// Runs Dijkstra's algorithm from a single source node.
/// Returns an array of minimum distances to all other nodes.
fn dijkstra(n: usize, graph: &Vec<Vec<(usize, i64)>>, start_node: usize) -> Vec<i64> {
    // Use i64::MAX / 2 as infinity to prevent overflow during addition
    const INF: i64 = i64::MAX / 2;
    let mut dist = vec![INF; n];

    // Min-heap implementation using Reverse wrapper
    let mut pq = BinaryHeap::new();

    dist[start_node] = 0;
    pq.push(Reverse((0, start_node)));

    while let Some(Reverse((d, u))) = pq.pop() {
        if d > dist[u] {
            continue;
        }

        for &(v, weight) in &graph[u] {
            let new_dist = dist[u] + weight;
            if new_dist < dist[v] {
                dist[v] = new_dist;
                pq.push(Reverse((new_dist, v)));
            }
        }
    }
    dist
}


fn solve(n_i64: i64, prices: Vec<i64>, roads: Vec<Vec<i64>>) -> Vec<i64> {
    let n = n_i64 as usize;

    // 1. Initialize Graphs
    // G_empty: for travel without apples (weight = cost)
    let mut g_empty: Vec<Vec<(usize, i64)>> = vec![Vec::new(); n];
    // G_full: for travel with apples (weight = cost * tax)
    let mut g_full: Vec<Vec<(usize, i64)>> = vec![Vec::new(); n];

    for road in roads {
        let u = road[0] as usize;
        let v = road[1] as usize;
        let cost = road[2];
        let tax = road[3];

        // Build G_empty (undirected)
        g_empty[u].push((v, cost));
        g_empty[v].push((u, cost));

        // Build G_full (undirected)
        // Note: cost * tax can be up to 10^9 * 100 = 10^11, fits in i64.
        let full_cost = cost * tax;
        g_full[u].push((v, full_cost));
        g_full[v].push((u, full_cost));
    }

    // 2. Calculate APSP using Dijkstra N times
    // DistEmpty[i][j]: Min cost from i to j empty-handed
    let mut dist_empty: Vec<Vec<i64>> = vec![vec![0; n]; n];
    // DistFull[i][j]: Min cost from i to j apple-handed
    let mut dist_full: Vec<Vec<i64>> = vec![vec![0; n]; n];

    for i in 0..n {
        // Run Dijkstra for empty travel starting at i
        let d_empty = dijkstra(n, &g_empty, i);
        for j in 0..n {
            dist_empty[i][j] = d_empty[j]; // Since roads are bidirectional, D(i, j) = D(j, i)
        }

        // Run Dijkstra for full travel starting at i
        let d_full = dijkstra(n, &g_full, i);
        for j in 0..n {
            dist_full[i][j] = d_full[j]; // Since roads are bidirectional, D(i, j) = D(j, i)
        }
    }

    // Re-adjusting the distance calculation: Since Dijkstra naturally finds D(start, end), 
    // and we iterate start=i, dist_empty[i] contains D(i, j) for all j.
    // We must ensure we store D(i, j) at [i][j].

    // Re-running the loop to properly fill the matrices D(i, j)
    let mut final_dist_empty: Vec<Vec<i64>> = vec![vec![0; n]; n];
    let mut final_dist_full: Vec<Vec<i64>> = vec![vec![0; n]; n];

    for i in 0..n {
        let d_empty_from_i = dijkstra(n, &g_empty, i);
        for j in 0..n {
            final_dist_empty[i][j] = d_empty_from_i[j];
        }

        let d_full_from_i = dijkstra(n, &g_full, i);
        for j in 0..n {
            final_dist_full[i][j] = d_full_from_i[j];
        }
    }


    // 3. Calculate minimum cost for each store i
    let mut ans: Vec<i64> = vec![0; n];

    for i in 0..n {
        // Option 1: Direct purchase
        let mut min_cost = prices[i];

        // Option 2: Travel to store j, buy, return to i
        // Total Cost = D_empty(i, j) + prices[j] + D_full(j, i)
        // Since roads are undirected, D_full(j, i) = D_full(i, j)

        for j in 0..n {
            if i == j {
                // This case is already covered by min_cost initialization (direct purchase)
                continue;
            }

            let d_empty_ij = final_dist_empty[i][j];
            let d_full_ji = final_dist_full[j][i]; // Travel from j to i while carrying apples

            // Check if paths exist (i.e., distances are not INF)
            if d_empty_ij != i64::MAX / 2 && d_full_ji != i64::MAX / 2 {
                // Total cost = Travel_Empty(i->j) + Price[j] + Travel_Full(j->i)
                let total_cost = d_empty_ij + prices[j] + d_full_ji;
                if total_cost < min_cost {
                    min_cost = total_cost;
                }
            }
        }
        ans[i] = min_cost;
    }

    ans
}

